import{_ as l,c as e,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"list Command: View Installed Skills | OpenSkills","description":"Learn to use the OpenSkills list command to view installed skills. Understand project and global location tags, deduplication rules, and troubleshooting.","frontmatter":{"title":"list Command: View Installed Skills | OpenSkills","sidebarTitle":"List Skills","subtitle":"list Command: View Installed Skills","description":"Learn to use the OpenSkills list command to view installed skills. Understand project and global location tags, deduplication rules, and troubleshooting.","tags":["Skill Management","Command Usage","CLI"],"prerequisite":["start-installation","start-first-skill"],"order":4},"headers":[],"relativePath":"numman-ali/openskills/platforms/list-skills/index.md","filePath":"numman-ali/openskills/platforms/list-skills/index.md"}'),t={name:"numman-ali/openskills/platforms/list-skills/index.md"};function n(o,s,r,p,d,c){return a(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="list-installed-skills" tabindex="-1">List Installed Skills <a class="header-anchor" href="#list-installed-skills" aria-label="Permalink to &quot;List Installed Skills&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>After completing this lesson, you will be able to:</p><ul><li>Use <code>openskills list</code> to view all installed skills</li><li>Understand the difference between <code>(project)</code> and <code>(global)</code> location tags</li><li>Quickly count the number of project skills and global skills</li><li>Verify if a skill is successfully installed</li></ul><h2 id="your-current-challenges" tabindex="-1">Your Current Challenges <a class="header-anchor" href="#your-current-challenges" aria-label="Permalink to &quot;Your Current Challenges&quot;">​</a></h2><p>After installing several skills, you may encounter these issues:</p><ul><li>&quot;Which skills did I just install? I forgot.&quot;</li><li>&quot;Did I install this skill to project or global?&quot;</li><li>&quot;Why can I see certain skills in project A but not in project B?&quot;</li><li>&quot;I want to delete some unused skills, but I don&#39;t know their specific names&quot;</li></ul><p>The <code>openskills list</code> command is designed to solve these confusions—it&#39;s like a &quot;directory&quot; for skills, helping you see all installed skills and their locations at a glance.</p><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Action</th></tr></thead><tbody><tr><td>Confirm successful installation after installing a skill</td><td>Run <code>openskills list</code> to check if the skill appears</td></tr><tr><td>Switch to a new project and check available skills</td><td>Run <code>openskills list</code> to see which project skills are available</td></tr><tr><td>Take inventory before cleaning up skills</td><td>Run <code>openskills list</code> to list all skills, then delete unneeded ones</td></tr><tr><td>Debug skill loading issues</td><td>Verify that skill names and installation locations are correct</td></tr></tbody></table><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>OpenSkills supports installing skills in <strong>4 locations</strong> (in search priority order):</p><ol><li><strong>project .agent/skills</strong> - Project-level general skills directory (multi-agent environment)</li><li><strong>global .agent/skills</strong> - Global general skills directory (multi-agent environment)</li><li><strong>project .claude/skills</strong> - Project-level Claude Code skills directory</li><li><strong>global .claude/skills</strong> - Global Claude Code skills directory</li></ol><p><code>openskills list</code> will:</p><ol><li>Traverse these 4 directories to find all skills</li><li><strong>Deduplicate</strong>: Display the same skill name only once (preferably showing project&#39;s)</li><li><strong>Sort</strong>: Project skills come first, global skills come last; within the same location, sort alphabetically</li><li><strong>Mark locations</strong>: Use <code>(project)</code> and <code>(global)</code> tags to distinguish</li><li><strong>Summary statistics</strong>: Display count of project skills, global skills, and total count</li></ol><div class="info custom-block"><p class="custom-block-title">Why is deduplication needed?</p><p>If you install the same skill (e.g., <code>pdf</code>) in both project and global, OpenSkills will preferentially use the project version. The list command only displays it once to avoid confusion.</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-list-all-installed-skills" tabindex="-1">Step 1: List All Installed Skills <a class="header-anchor" href="#step-1-list-all-installed-skills" aria-label="Permalink to &quot;Step 1: List All Installed Skills&quot;">​</a></h3><p><strong>Why</strong> Quickly view which skills are available in the current environment</p><p>Run the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>What You Should See</strong></p><p>If no skills are installed, it will display:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Available Skills:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>No skills installed.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Install skills:</span></span>
<span class="line"><span>  npx openskills install anthropics/skills         # Project (default)</span></span>
<span class="line"><span>  npx openskills install owner/skill --global     # Global (advanced)</span></span></code></pre></div><p>If skills are already installed, you&#39;ll see something like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Available Skills:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  pdf                         (project)</span></span>
<span class="line"><span>    Comprehensive PDF manipulation toolkit for extracting text and tables...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  code-analyzer                (project)</span></span>
<span class="line"><span>    Static code analysis tool for identifying security vulnerabilities...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  email-reader                 (global)</span></span>
<span class="line"><span>    Read email content and attachments via IMAP protocol...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary: 2 project, 1 global (3 total)</span></span></code></pre></div><h3 id="step-2-understand-output-format" tabindex="-1">Step 2: Understand Output Format <a class="header-anchor" href="#step-2-understand-output-format" aria-label="Permalink to &quot;Step 2: Understand Output Format&quot;">​</a></h3><p><strong>Why</strong> Understanding what each line represents helps you quickly locate the information you need</p><p>Output format explanation:</p><table tabindex="0"><thead><tr><th>Part</th><th>Description</th></tr></thead><tbody><tr><td><code>pdf</code></td><td>Skill name (extracted from the <code>name</code> field in SKILL.md)</td></tr><tr><td><code>(project)</code></td><td>Location tag: blue indicates project-level skill, gray indicates global skill</td></tr><tr><td><code>Comprehensive PDF...</code></td><td>Skill description (extracted from the <code>description</code> field in SKILL.md)</td></tr><tr><td><code>Summary: 2 project, 1 global (3 total)</code></td><td>Summary statistics: count of project skills, global skills, and total</td></tr></tbody></table><h3 id="step-3-verify-location-tags" tabindex="-1">Step 3: Verify Location Tags <a class="header-anchor" href="#step-3-verify-location-tags" aria-label="Permalink to &quot;Step 3: Verify Location Tags&quot;">​</a></h3><p><strong>Why</strong> Confirm that skills are installed in the expected location, avoiding confusion about &quot;why can&#39;t I see this skill in this project&quot;</p><p>Try the following operations to understand location tags:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 1. Install a project-level skill</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 2. View the list (should show project tag)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 3. Install a global skill</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 4. View the list again (two pdf skills, only displayed once, tag is project)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p><strong>What You Should See</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Available Skills:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  pdf                         (project)</span></span>
<span class="line"><span>    Comprehensive PDF manipulation toolkit for extracting text...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary: 1 project, 0 global (1 total)</span></span></code></pre></div><p>Even if the same skill is installed in both global and project, the list command will only display it once because the project version has higher priority.</p><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><p>Confirm the following:</p><ul><li>[ ] Running <code>openskills list</code> displays the list of installed skills</li><li>[ ] Can distinguish between <code>(project)</code> and <code>(global)</code> tags (different colors: blue vs gray)</li><li>[ ] Summary statistics are correct (project skills + global skills = total)</li><li>[ ] Understand the rule that the same skill name is only displayed once</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="common-issue-1-cannot-find-just-installed-skill" tabindex="-1">Common Issue 1: Cannot Find Just-Installed Skill <a class="header-anchor" href="#common-issue-1-cannot-find-just-installed-skill" aria-label="Permalink to &quot;Common Issue 1: Cannot Find Just-Installed Skill&quot;">​</a></h3><p><strong>Symptom</strong>: The <code>install</code> command succeeded, but <code>list</code> doesn&#39;t show it</p><p><strong>Troubleshooting Steps</strong>:</p><ol><li>Check if you&#39;re in the correct project directory (project skills are only visible to the current project)</li><li>Confirm if it was installed globally (using the <code>--global</code> flag)</li><li>Verify the installation location:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check project directory</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .claude/skills/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check global directory</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/skills/</span></span></code></pre></div><h3 id="common-issue-2-see-strange-skill-names" tabindex="-1">Common Issue 2: See Strange Skill Names <a class="header-anchor" href="#common-issue-2-see-strange-skill-names" aria-label="Permalink to &quot;Common Issue 2: See Strange Skill Names&quot;">​</a></h3><p><strong>Symptom</strong>: The skill name is not what you expected (e.g., folder name vs name in SKILL.md)</p><p><strong>Cause</strong>: OpenSkills uses the <code>name</code> field in SKILL.md as the skill name, not the folder name</p><p><strong>Solution</strong>: Check the frontmatter in SKILL.md:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pdf</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # This is the name displayed by the list command</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Comprehensive PDF manipulation toolkit...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><h3 id="common-issue-3-description-not-fully-displayed" tabindex="-1">Common Issue 3: Description Not Fully Displayed <a class="header-anchor" href="#common-issue-3-description-not-fully-displayed" aria-label="Permalink to &quot;Common Issue 3: Description Not Fully Displayed&quot;">​</a></h3><p><strong>Symptom</strong>: The skill description is truncated</p><p><strong>Cause</strong>: This is due to terminal width limitations and doesn&#39;t affect the skill content</p><p><strong>Solution</strong>: View the SKILL.md file directly to get the complete description</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>The <code>openskills list</code> command is the &quot;directory&quot; command for skill management, helping you:</p><ul><li>📋 <strong>View all skills</strong>: See installed skills at a glance</li><li>🏷️ <strong>Distinguish location tags</strong>: <code>(project)</code> indicates project-level, <code>(global)</code> indicates global-level</li><li>📊 <strong>Summary statistics</strong>: Quickly understand the count of project and global skills</li><li>🔍 <strong>Troubleshoot issues</strong>: Verify if skills are successfully installed and locate skill positions</li></ul><p>Core rules:</p><ol><li>Same skill name is only displayed once (project takes precedence)</li><li>Project skills come first, global skills come last</li><li>Within the same location, sorted alphabetically</li></ol><h2 id="up-next" tabindex="-1">Up Next <a class="header-anchor" href="#up-next" aria-label="Permalink to &quot;Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../update-skills/">Updating Skills</a></strong>.</p><p>You will learn:</p><ul><li>How to refresh installed skills from source repository</li><li>Batch update all skills</li><li>Handle old skills without metadata</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>list command implementation</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/commands/list.ts" target="_blank" rel="noreferrer"><code>src/commands/list.ts</code></a></td><td>7-43</td></tr><tr><td>Find all skills</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/skills.ts" target="_blank" rel="noreferrer"><code>src/utils/skills.ts</code></a></td><td>30-64</td></tr><tr><td>Search directory configuration</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/utils/dirs.ts" target="_blank" rel="noreferrer"><code>src/utils/dirs.ts</code></a></td><td>18-25</td></tr><tr><td>Skill type definition</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-6</td></tr></tbody></table><p><strong>Key Functions</strong>:</p><ul><li><code>listSkills()</code>: List all installed skills with formatted output</li><li><code>findAllSkills()</code>: Traverse 4 search directories and collect all skills</li><li><code>getSearchDirs()</code>: Return 4 search directory paths (in priority order)</li></ul><p><strong>Key Constants</strong>:</p><ul><li>None (search directory paths are dynamically calculated)</li></ul><p><strong>Core Logic</strong>:</p><ol><li><strong>Deduplication mechanism</strong>: Use <code>Set</code> to track processed skill names (skills.ts:32-33, 43, 57)</li><li><strong>Location determination</strong>: Determine if it&#39;s a project directory via <code>dir.includes(process.cwd())</code> (skills.ts:48)</li><li><strong>Sorting rules</strong>: Project first, same location in alphabetical order (list.ts:21-26)</li></ol></details>`,65)])])}const u=l(t,[["render",n]]);export{k as __pageData,u as default};
